{ Launch Interceptor Program - Knight & Leveson (1986)
  Implements the DECIDE procedure and JSON I/O wrapper.
  Archival source: lipdecide.pas
}

program LIPDecide;

{$mode objfpc}{$H+}

uses
  SysUtils, Math;

{ ---- Constants and types matching the specification ---- }

const
  PI       = 3.1415926535;
  MAXPTS   = 100;
  NLICS    = 15;

type
  COMPTYPE  = (LT, EQ, GT);
  CONNECTORS = (NOTUSED, ORR, ANDD);

  COORDINATE = array[1..MAXPTS] of real;
  CMATRIX    = array[1..NLICS, 1..NLICS] of CONNECTORS;
  BMATRIX    = array[1..NLICS, 1..NLICS] of boolean;
  VECTOR     = array[1..NLICS] of boolean;

  TParameters = record
    LENGTH1 : real;
    RADIUS1 : real;
    EPSILON : real;
    AREA1   : real;
    Q_PTS   : integer;
    QUADS   : integer;
    DIST    : real;
    N_PTS   : integer;
    K_PTS   : integer;
    A_PTS   : integer;
    B_PTS   : integer;
    C_PTS   : integer;
    D_PTS   : integer;
    E_PTS   : integer;
    F_PTS   : integer;
    G_PTS   : integer;
    LENGTH2 : real;
    RADIUS2 : real;
    AREA2   : real;
  end;

{ ---- Global variables ---- }
var
  X          : COORDINATE;
  Y          : COORDINATE;
  NUMPOINTS  : integer;
  PARAMETERS : TParameters;
  LCM        : CMATRIX;
  PUM        : BMATRIX;
  CMV        : VECTOR;
  FUV        : VECTOR;
  LAUNCH     : boolean;

{ ---- REALCOMPARE - fixed reference behavior ---- }
function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;
  eps  := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

{ ---- Geometry helpers ---- }

{ Euclidean distance between two points }
function Dist2(x1, y1, x2, y2: real): real;
begin
  Dist2 := Sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
end;

{ Absolute value of twice the signed triangle area (= |det|) }
function TriArea2(ax, ay, bx, by, cx, cy: real): real;
begin
  TriArea2 := Abs((bx - ax) * (cy - ay) - (cx - ax) * (by - ay));
end;

{ Circumradius of the triangle (ax,ay),(bx,by),(cx,cy).
  Returns 0 when the triangle is degenerate (collinear). }
function CircumRadius(ax, ay, bx, by, cx, cy: real): real;
var
  a, b, c, s, area: real;
begin
  a := Dist2(bx, by, cx, cy);
  b := Dist2(ax, ay, cx, cy);
  c := Dist2(ax, ay, bx, by);
  area := TriArea2(ax, ay, bx, by, cx, cy) / 2.0;
  if REALCOMPARE(area, 0.0) = EQ then
  begin
    { Degenerate / collinear: minimal enclosing circle = half the longest side }
    s := a;
    if b > s then s := b;
    if c > s then s := c;
    CircumRadius := s / 2.0;
  end
  else
    CircumRadius := (a * b * c) / (4.0 * area);
end;

{ Angle at vertex (vx,vy) looking from (ax,ay) and to (cx,cy).
  Returns -1.0 if either arm is zero-length (undefined angle). }
function AngleAtVertex(ax, ay, vx, vy, cx, cy: real): real;
var
  d1x, d1y, d2x, d2y, dot, len1, len2: real;
begin
  d1x := ax - vx;
  d1y := ay - vy;
  d2x := cx - vx;
  d2y := cy - vy;
  len1 := Sqrt(d1x * d1x + d1y * d1y);
  len2 := Sqrt(d2x * d2x + d2y * d2y);
  if (REALCOMPARE(len1, 0.0) = EQ) or (REALCOMPARE(len2, 0.0) = EQ) then
  begin
    AngleAtVertex := -1.0;
    Exit;
  end;
  dot := (d1x * d2x + d1y * d2y) / (len1 * len2);
  { Clamp to [-1,1] to guard floating-point noise in arccos }
  if dot > 1.0  then dot :=  1.0;
  if dot < -1.0 then dot := -1.0;
  AngleAtVertex := ArcCos(dot);
end;

{ Distance from point (px,py) to the line through (ax,ay)-(bx,by).
  If the endpoints are coincident, returns the distance to that point. }
function PointToLineDist(px, py, ax, ay, bx, by: real): real;
var
  dx, dy, len, area: real;
begin
  dx := bx - ax;
  dy := by - ay;
  len := Sqrt(dx * dx + dy * dy);
  if REALCOMPARE(len, 0.0) = EQ then
  begin
    PointToLineDist := Dist2(px, py, ax, ay);
    Exit;
  end;
  area := Abs(dx * (ay - py) - (ax - px) * dy);
  PointToLineDist := area / len;
end;

{ Quadrant of a point using spec priority rules }
function Quadrant(px, py: real): integer;
begin
  if (REALCOMPARE(px, 0.0) <> LT) and (REALCOMPARE(py, 0.0) <> LT) then
    Quadrant := 1    { I: x>=0, y>=0 }
  else if (REALCOMPARE(px, 0.0) = LT) and (REALCOMPARE(py, 0.0) <> LT) then
    Quadrant := 2    { II: x<0, y>=0 }
  else if (REALCOMPARE(px, 0.0) = LT) and (REALCOMPARE(py, 0.0) = LT) then
    Quadrant := 3    { III: x<0, y<0 }
  else
    Quadrant := 4;   { IV: x>=0, y<0 }
end;

{ ---- LIC evaluations ---- }

{ LIC 1: two consecutive points > LENGTH1 apart }
function LIC1: boolean;
var i: integer;
begin
  LIC1 := False;
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(Dist2(X[i], Y[i], X[i+1], Y[i+1]), PARAMETERS.LENGTH1) = GT then
    begin
      LIC1 := True;
      Exit;
    end;
end;

{ LIC 2: three consecutive points not all in/on circle of RADIUS1 }
function LIC2: boolean;
var i: integer; r: real;
begin
  LIC2 := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    r := CircumRadius(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
    begin
      LIC2 := True;
      Exit;
    end;
  end;
end;

{ LIC 3: three consecutive points form angle < PI-EPSILON or > PI+EPSILON }
function LIC3: boolean;
var i: integer; angle: real;
begin
  LIC3 := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    angle := AngleAtVertex(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if angle < 0.0 then Continue;  { undefined }
    if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
    begin
      LIC3 := True;
      Exit;
    end;
  end;
end;

{ LIC 4: three consecutive points form triangle with area > AREA1 }
function LIC4: boolean;
var i: integer; area: real;
begin
  LIC4 := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := TriArea2(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]) / 2.0;
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      LIC4 := True;
      Exit;
    end;
  end;
end;

{ LIC 5: Q_PTS consecutive points in more than QUADS quadrants }
function LIC5: boolean;
var
  i, j, q, seen: integer;
  quadsFound: array[1..4] of boolean;
begin
  LIC5 := False;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for q := 1 to 4 do quadsFound[q] := False;
    for j := i to i + PARAMETERS.Q_PTS - 1 do
      quadsFound[Quadrant(X[j], Y[j])] := True;
    seen := 0;
    for q := 1 to 4 do
      if quadsFound[q] then Inc(seen);
    if seen > PARAMETERS.QUADS then
    begin
      LIC5 := True;
      Exit;
    end;
  end;
end;

{ LIC 6: two consecutive points with X[j] - X[i] < 0, j = i+1 }
function LIC6: boolean;
var i: integer;
begin
  LIC6 := False;
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[i+1] - X[i], 0.0) = LT then
    begin
      LIC6 := True;
      Exit;
    end;
end;

{ LIC 7: N_PTS consecutive points, at least one > DIST from line joining first/last }
function LIC7: boolean;
var
  i, j: integer;
  d: real;
begin
  LIC7 := False;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    for j := i + 1 to i + PARAMETERS.N_PTS - 2 do
    begin
      d := PointToLineDist(X[j], Y[j],
                           X[i], Y[i],
                           X[i + PARAMETERS.N_PTS - 1], Y[i + PARAMETERS.N_PTS - 1]);
      if REALCOMPARE(d, PARAMETERS.DIST) = GT then
      begin
        LIC7 := True;
        Exit;
      end;
    end;
  end;
end;

{ LIC 8: two points separated by K_PTS, distance > LENGTH1 }
function LIC8: boolean;
var i: integer; d: real;
begin
  LIC8 := False;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    d := Dist2(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      LIC8 := True;
      Exit;
    end;
  end;
end;

{ LIC 9: three points separated by A_PTS and B_PTS, not in/on circle of RADIUS1 }
function LIC9: boolean;
var i, j, k: integer; r: real;
begin
  LIC9 := False;
  if NUMPOINTS < 5 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    r := CircumRadius(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
    begin
      LIC9 := True;
      Exit;
    end;
  end;
end;

{ LIC 10: three points separated by C_PTS and D_PTS, angle < PI-EPSILON or > PI+EPSILON }
function LIC10: boolean;
var i, j, k: integer; angle: real;
begin
  LIC10 := False;
  if NUMPOINTS < 5 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;
    angle := AngleAtVertex(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if angle < 0.0 then Continue;
    if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
    begin
      LIC10 := True;
      Exit;
    end;
  end;
end;

{ LIC 11: three points separated by E_PTS and F_PTS, triangle area > AREA1 }
function LIC11: boolean;
var i, j, k: integer; area: real;
begin
  LIC11 := False;
  if NUMPOINTS < 5 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    area := TriArea2(X[i], Y[i], X[j], Y[j], X[k], Y[k]) / 2.0;
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      LIC11 := True;
      Exit;
    end;
  end;
end;

{ LIC 12: two points separated by G_PTS, X[j] - X[i] < 0 }
function LIC12: boolean;
var i: integer;
begin
  LIC12 := False;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
    if REALCOMPARE(X[i + PARAMETERS.G_PTS + 1] - X[i], 0.0) = LT then
    begin
      LIC12 := True;
      Exit;
    end;
end;

{ LIC 13: two parts - K_PTS separated pair > LENGTH1 AND another pair < LENGTH2 }
function LIC13: boolean;
var i: integer; d: real; part1, part2: boolean;
begin
  LIC13 := False;
  if NUMPOINTS < 3 then Exit;
  part1 := False;
  part2 := False;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    d := Dist2(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then part1 := True;
    if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then part2 := True;
  end;
  LIC13 := part1 and part2;
end;

{ LIC 14: A_PTS/B_PTS separated triple: part1 - not in RADIUS1; part2 - in RADIUS2 }
function LIC14: boolean;
var i, j, k: integer; r: real; part1, part2: boolean;
begin
  LIC14 := False;
  if NUMPOINTS < 5 then Exit;
  part1 := False;
  part2 := False;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    r := CircumRadius(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then part1 := True;
    if REALCOMPARE(r, PARAMETERS.RADIUS2) <> GT then part2 := True;
  end;
  LIC14 := part1 and part2;
end;

{ LIC 15: E_PTS/F_PTS separated triple: part1 - area > AREA1; part2 - area < AREA2 }
function LIC15: boolean;
var i, j, k: integer; area: real; part1, part2: boolean;
begin
  LIC15 := False;
  if NUMPOINTS < 5 then Exit;
  part1 := False;
  part2 := False;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    area := TriArea2(X[i], Y[i], X[j], Y[j], X[k], Y[k]) / 2.0;
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then part1 := True;
    if REALCOMPARE(area, PARAMETERS.AREA2) = LT then part2 := True;
  end;
  LIC15 := part1 and part2;
end;

{ ---- Main DECIDE procedure ---- }
procedure DECIDE;
var i, j: integer; allTrue: boolean;
begin
  { 1. Compute CMV }
  CMV[1]  := LIC1;
  CMV[2]  := LIC2;
  CMV[3]  := LIC3;
  CMV[4]  := LIC4;
  CMV[5]  := LIC5;
  CMV[6]  := LIC6;
  CMV[7]  := LIC7;
  CMV[8]  := LIC8;
  CMV[9]  := LIC9;
  CMV[10] := LIC10;
  CMV[11] := LIC11;
  CMV[12] := LIC12;
  CMV[13] := LIC13;
  CMV[14] := LIC14;
  CMV[15] := LIC15;

  { 2. Compute PUM off-diagonal elements }
  for i := 1 to NLICS do
    for j := 1 to NLICS do
    begin
      if i = j then
        { diagonal supplied by input - do not overwrite }
      else
        case LCM[i, j] of
          NOTUSED : PUM[i, j] := True;
          ORR     : PUM[i, j] := CMV[i] or CMV[j];
          ANDD    : PUM[i, j] := CMV[i] and CMV[j];
        end;
    end;

  { 3. Compute FUV }
  for i := 1 to NLICS do
  begin
    if not PUM[i, i] then
      FUV[i] := True
    else
    begin
      allTrue := True;
      for j := 1 to NLICS do
        if not PUM[i, j] then
        begin
          allTrue := False;
          Break;
        end;
      FUV[i] := allTrue;
    end;
  end;

  { 4. Launch decision }
  LAUNCH := True;
  for i := 1 to NLICS do
    if not FUV[i] then
    begin
      LAUNCH := False;
      Break;
    end;
end;

{ ================================================================
  JSON I/O wrapper - minimal hand-rolled parser for the input
  schema and emitter for the output schema.
  ================================================================ }

{ --- Tiny JSON parser state --- }
var
  JsonInput : string;
  JsonPos   : integer;

procedure SkipWS;
begin
  while (JsonPos <= Length(JsonInput)) and
        (JsonInput[JsonPos] in [' ', #9, #10, #13]) do
    Inc(JsonPos);
end;

function PeekChar: char;
begin
  SkipWS;
  if JsonPos <= Length(JsonInput) then
    PeekChar := JsonInput[JsonPos]
  else
    PeekChar := #0;
end;

function ReadChar: char;
begin
  SkipWS;
  if JsonPos <= Length(JsonInput) then
  begin
    ReadChar := JsonInput[JsonPos];
    Inc(JsonPos);
  end
  else
    ReadChar := #0;
end;

procedure Expect(c: char);
var ch: char;
begin
  ch := ReadChar;
  if ch <> c then
  begin
    WriteLn(StdErr, 'JSON parse error: expected "', c, '" got "', ch,
            '" at pos ', JsonPos - 1);
    Halt(1);
  end;
end;

function ReadString: string;
var s: string; ch: char; esc: boolean;
begin
  Expect('"');
  s   := '';
  esc := False;
  while JsonPos <= Length(JsonInput) do
  begin
    ch := JsonInput[JsonPos];
    Inc(JsonPos);
    if esc then
    begin
      case ch of
        'n': s := s + #10;
        't': s := s + #9;
        'r': s := s + #13;
        else s := s + ch;
      end;
      esc := False;
    end
    else if ch = '\' then
      esc := True
    else if ch = '"' then
      Break
    else
      s := s + ch;
  end;
  ReadString := s;
end;

function ReadNumber: real;
var s: string; ch: char; code: integer; v: real;
begin
  SkipWS;
  s := '';
  while JsonPos <= Length(JsonInput) do
  begin
    ch := JsonInput[JsonPos];
    if ch in ['-', '+', '0'..'9', '.', 'e', 'E'] then
    begin
      s := s + ch;
      Inc(JsonPos);
    end
    else
      Break;
  end;
  Val(s, v, code);
  if code <> 0 then
  begin
    WriteLn(StdErr, 'JSON number parse error: "', s, '"');
    Halt(1);
  end;
  ReadNumber := v;
end;

function ReadInt: integer;
begin
  ReadInt := Round(ReadNumber);
end;

function ReadBool: boolean;
begin
  SkipWS;
  if Copy(JsonInput, JsonPos, 4) = 'true' then
  begin
    Inc(JsonPos, 4);
    ReadBool := True;
  end
  else if Copy(JsonInput, JsonPos, 5) = 'false' then
  begin
    Inc(JsonPos, 5);
    ReadBool := False;
  end
  else
  begin
    WriteLn(StdErr, 'JSON bool parse error at pos ', JsonPos);
    Halt(1);
  end;
end;

{ Read a connector string and return the enum value }
function ReadConnector: CONNECTORS;
var s: string;
begin
  s := ReadString;
  if s = 'NOTUSED' then ReadConnector := NOTUSED
  else if s = 'ORR'     then ReadConnector := ORR
  else if s = 'ANDD'    then ReadConnector := ANDD
  else
  begin
    WriteLn(StdErr, 'Unknown connector: ', s);
    Halt(1);
  end;
end;

{ Read a JSON array of reals into X/Y coordinate arrays, returns count }
procedure ReadRealArray(var arr: COORDINATE; n: integer);
var i: integer;
begin
  Expect('[');
  for i := 1 to n do
  begin
    arr[i] := ReadNumber;
    if i < n then Expect(',');
  end;
  Expect(']');
end;

{ Read bool array into VECTOR }
procedure ReadBoolArray(var v: VECTOR; n: integer);
var i: integer;
begin
  Expect('[');
  for i := 1 to n do
  begin
    v[i] := ReadBool;
    if i < n then Expect(',');
  end;
  Expect(']');
end;

{ Skip a JSON value (for unknown keys) }
procedure SkipValue; forward;

procedure SkipObject;
var ch: char;
begin
  Expect('{');
  SkipWS;
  if PeekChar = '}' then begin ReadChar; Exit; end;
  repeat
    ReadString;   { key }
    Expect(':');
    SkipValue;    { value }
    SkipWS;
    ch := PeekChar;
    if ch = ',' then ReadChar;
  until ch <> ',';
  Expect('}');
end;

procedure SkipArray;
var ch: char;
begin
  Expect('[');
  SkipWS;
  if PeekChar = ']' then begin ReadChar; Exit; end;
  repeat
    SkipValue;
    SkipWS;
    ch := PeekChar;
    if ch = ',' then ReadChar;
  until ch <> ',';
  Expect(']');
end;

procedure SkipValue;
var ch: char;
begin
  SkipWS;
  ch := PeekChar;
  case ch of
    '{': SkipObject;
    '[': SkipArray;
    '"': ReadString;
    't','f': ReadBool;
    else ReadNumber;
  end;
end;

{ Parse the full input JSON object from JsonInput }
procedure ParseInput;
var key: string; i, j: integer; ch: char;
begin
  Expect('{');
  SkipWS;
  repeat
    key := ReadString;
    Expect(':');
    if key = 'numpoints' then
      NUMPOINTS := ReadInt
    else if key = 'x' then
      ReadRealArray(X, NUMPOINTS)
    else if key = 'y' then
      ReadRealArray(Y, NUMPOINTS)
    else if key = 'parameters' then
    begin
      Expect('{');
      SkipWS;
      repeat
        key := ReadString;
        Expect(':');
        if key = 'LENGTH1' then PARAMETERS.LENGTH1 := ReadNumber
        else if key = 'RADIUS1' then PARAMETERS.RADIUS1 := ReadNumber
        else if key = 'EPSILON' then PARAMETERS.EPSILON := ReadNumber
        else if key = 'AREA1'   then PARAMETERS.AREA1   := ReadNumber
        else if key = 'Q_PTS'   then PARAMETERS.Q_PTS   := ReadInt
        else if key = 'QUADS'   then PARAMETERS.QUADS   := ReadInt
        else if key = 'DIST'    then PARAMETERS.DIST    := ReadNumber
        else if key = 'N_PTS'   then PARAMETERS.N_PTS   := ReadInt
        else if key = 'K_PTS'   then PARAMETERS.K_PTS   := ReadInt
        else if key = 'A_PTS'   then PARAMETERS.A_PTS   := ReadInt
        else if key = 'B_PTS'   then PARAMETERS.B_PTS   := ReadInt
        else if key = 'C_PTS'   then PARAMETERS.C_PTS   := ReadInt
        else if key = 'D_PTS'   then PARAMETERS.D_PTS   := ReadInt
        else if key = 'E_PTS'   then PARAMETERS.E_PTS   := ReadInt
        else if key = 'F_PTS'   then PARAMETERS.F_PTS   := ReadInt
        else if key = 'G_PTS'   then PARAMETERS.G_PTS   := ReadInt
        else if key = 'LENGTH2' then PARAMETERS.LENGTH2 := ReadNumber
        else if key = 'RADIUS2' then PARAMETERS.RADIUS2 := ReadNumber
        else if key = 'AREA2'   then PARAMETERS.AREA2   := ReadNumber
        else SkipValue;
        SkipWS;
        ch := PeekChar;
        if ch = ',' then ReadChar;
      until ch <> ',';
      Expect('}');
    end
    else if key = 'lcm' then
    begin
      Expect('[');
      for i := 1 to NLICS do
      begin
        Expect('[');
        for j := 1 to NLICS do
        begin
          LCM[i, j] := ReadConnector;
          if j < NLICS then Expect(',');
        end;
        Expect(']');
        if i < NLICS then Expect(',');
      end;
      Expect(']');
    end
    else if key = 'pum_diag' then
    begin
      Expect('[');
      for i := 1 to NLICS do
      begin
        PUM[i, i] := ReadBool;
        if i < NLICS then Expect(',');
      end;
      Expect(']');
    end
    else
      SkipValue;
    SkipWS;
    ch := PeekChar;
    if ch = ',' then ReadChar;
  until ch <> ',';
  Expect('}');
end;

{ ---- JSON output helpers ---- }

procedure WriteBoolVal(b: boolean);
begin
  if b then Write('true') else Write('false');
end;

procedure WriteOutput;
var i, j: integer;
begin
  Write('{');

  { cmv }
  Write('"cmv":[');
  for i := 1 to NLICS do
  begin
    WriteBoolVal(CMV[i]);
    if i < NLICS then Write(',');
  end;
  Write('],');

  { pum }
  Write('"pum":[');
  for i := 1 to NLICS do
  begin
    Write('[');
    for j := 1 to NLICS do
    begin
      WriteBoolVal(PUM[i, j]);
      if j < NLICS then Write(',');
    end;
    Write(']');
    if i < NLICS then Write(',');
  end;
  Write('],');

  { fuv }
  Write('"fuv":[');
  for i := 1 to NLICS do
  begin
    WriteBoolVal(FUV[i]);
    if i < NLICS then Write(',');
  end;
  Write('],');

  { launch }
  Write('"launch":');
  WriteBoolVal(LAUNCH);

  WriteLn('}');
end;

{ ---- Main program ---- }
var
  line: string;
begin
  { Read all of stdin into JsonInput }
  JsonInput := '';
  while not EOF(Input) do
  begin
    ReadLn(Input, line);
    JsonInput := JsonInput + line + ' ';
  end;

  JsonPos := 1;
  ParseInput;
  DECIDE;
  WriteOutput;
end.
